const tasks = $input.all().map(item => item.json);

const IST_OFFSET = 5.5 * 60 * 60 * 1000;
const nowUTC = Date.now();
const nowIST = nowUTC + IST_OFFSET;
const nowISTDate = new Date(nowIST);

const dateStr = nowISTDate.toLocaleDateString("en-IN", {
  weekday: "short", day: "numeric", month: "short",
  timeZone: "Asia/Kolkata"
});

const listName = $('Loop Over Items').item.json.list_name || "Tasks";

// Handle empty response
if (!tasks || tasks.length === 0 || !tasks[0].id) {
  return [{ json: { message: `📋 *${listName} — ${dateStr}*\n\nNo tasks for this week. ✅` } }];
}

const todayStart = Date.UTC(
  nowISTDate.getUTCFullYear(),
  nowISTDate.getUTCMonth(),
  nowISTDate.getUTCDate()
) - IST_OFFSET;

const todayEnd = todayStart + 86400000;

const overdue = [];
const today = [];
const week = [];

for (const task of tasks) {
  const due = parseInt(task.due_date);

  if (due < todayStart) {
    overdue.push(task.name);
  } else if (due < todayEnd) {
    today.push(task.name);
  } else {
    week.push(task.name);
  }
}

const formatList = (arr) =>
  arr.map((line, i) => `${i + 1}. ${line}`).join("\n");

let msg = `📋 *${listName} — ${dateStr}*\n`;

if (overdue.length > 0) {
  msg += `\n🔴 *Overdue (${overdue.length})*\n`;
  msg += formatList(overdue);
}

if (today.length > 0) {
  msg += `\n\n📅 *Today (${today.length})*\n`;
  msg += formatList(today);
}

if (week.length > 0) {
  msg += `\n\n📆 *This Week (${week.length})*\n`;
  msg += formatList(week);
}

if (overdue.length === 0 && today.length === 0 && week.length === 0) {
  msg += "\n\nNo tasks for this week. ✅";
}

msg += `\n\n_${overdue.length + today.length + week.length} tasks total_`;

return [{ json: { message: msg } }];

