{
  "type": "object",
  "properties": {
    "task_name": {
      "type": "string",
      "description": "Short actionable task title without names, dates, or priority words"
    },
    "task_description": {
      "type": "string",
      "description": "1-2 sentences preserving names and context stripped from task name, ending with Original: quote. Must not repeat task name"
    },
    "assignee_id": {
      "type": "integer",
      "enum": [100993403, 88904698],
      "description": "Must be one of the predefined assignee IDs"
    },
    "priority": {
      "type": "integer",
      "enum": [1, 2, 3],
      "description": "1 = urgent, 2 = high/default, 3 = low"
    },
    "due_date": {
      "type": "string",
      "pattern": "^\\d{4}-\\d{2}-\\d{2}T00:00:00$",
      "description": "ISO format date in YYYY-MM-DDT00:00:00 format (IST timezone)"
    },
    "list_id": {
      "type": "integer",
      "enum": [901613829435, 901613780278],
      "description": "ClickUp List ID based on routing rules"
    }
  },
  "required": ["task_name", "task_description", "assignee_id", "priority", "due_date", "list_id"],
  "additionalProperties": false
}

